import type React from 'react';
import { TestComponentProps } from 'src/types/test-component';
export type ButtonColorVariants = 'primary' | 'secondary' | 'ghost' | 'inverse' | 'danger' | 'accent-black' | 'accent-white'
/** @deprecated Use 'primary' instead */
 | 'contained'
/** @deprecated Use 'secondary' instead */
 | 'outlined'
/** @deprecated Use 'ghost' instead */
 | 'plain'
/** @deprecated Use 'inverse' instead */
 | 'overlay';
export type ButtonSizeVariants = 'small' | 'medium' | 'large';
type MergedHTMLAttributes = React.HTMLAttributes<HTMLElement> & React.ButtonHTMLAttributes<HTMLElement> & React.AnchorHTMLAttributes<HTMLElement>;
export interface ButtonProps extends MergedHTMLAttributes, TestComponentProps {
    /**
     * Вариант кнопки.
     */
    variant?: ButtonColorVariants;
    /**
     * Ссылка для перехода.
     */
    href?: string;
    /**
     * Размер кнопки
     */
    size?: ButtonSizeVariants;
    /**
     * Компонент иконки, отображается в начале названия кнопки
     */
    startIcon?: React.ReactNode;
    /**
     * Компонент иконки, отображается в конце названия кнопки
     */
    endIcon?: React.ReactNode;
    /**
     * если передан - кнопка займет всю доступную ширину родителя
     */
    fullWidth?: boolean;
}
export {};
